    def _select_font_family(self, preferred_families):
        try:
            installed = {f.lower(): f for f in tkfont.families(self.root)}
        except Exception:
            installed = {}
        for fam in preferred_families:
            hit = installed.get(str(fam).lower())
            if hit:
                return hit
        return "Segoe UI"

    def _configure_typography(self):
        arabic_family = self._select_font_family([
            "IBM Plex Sans Arabic",
            "Cairo",
            "Noto Sans Arabic",
            "Noto Naskh Arabic",
            "Tahoma",
            "Segoe UI",
            "Arial",
        ])
        mono_family = self._select_font_family(["JetBrains Mono", "Consolas", "Courier New"])
        FONTS.update({
            'header': (arabic_family, 24, 'bold'),
            'title': (arabic_family, 15, 'bold'),
            'subtitle': (arabic_family, 11),
            'label': (arabic_family, 12, 'bold'),
            'normal': (arabic_family, 11),
            'button': (arabic_family, 11, 'bold'),
            'tree': (arabic_family, 12),
            'caption': (arabic_family, 10, 'bold'),
            'mono': (mono_family, 10),
        })
        self.root.option_add("*Font", f"{arabic_family} 11")
        # Slight DPI scaling for clearer text on modern displays.
        try:
            # Keep scaling close to 1.0 to preserve pixel-consistent UI metrics.
            self.root.tk.call('tk', 'scaling', 1.05)
        except Exception:
            pass
        self.root.option_add("*Button.Cursor", "hand2")
        self.root.option_add("*Button.HighlightThickness", 0)
        self.root.option_add("*Button.BorderWidth", 0)

