    def _set_table_density_from_label(self, _event=None):
        label = str(self.table_density_var.get() or "").strip().lower()
        if "compact" in label or "مضغوط" in label:
            density = "compact"
        else:
            density = "comfortable"
        self._apply_table_density(density)

    def _apply_table_density(self, density="comfortable"):
        rowheight = 30 if density == "compact" else 40
        font = FONTS['normal'] if density == "compact" else FONTS['tree']
        style = ttk.Style(self.root)
        style.configure("Treeview", rowheight=rowheight, font=font)
        style.configure("Treeview.Heading", font=FONTS['label'])
        try:
            self.workspace_hint_label.configure(
                text="وضع عرض مضغوط" if (self.current_lang == 'ar' and density == "compact") else ("Compact view" if density == "compact" else "")
            )
        except Exception:
            pass

    def _sync_workspace_nav_state(self):
        current_key = self._current_notebook_tab_key()
        buttons = getattr(self, "workspace_nav_buttons", {}) or {}
        for key, btn in buttons.items():
            selected = key == current_key
            if hasattr(self, "nav_rail"):
                # Premium rail style
                try:
                    styles = getattr(btn, "_rail_styles", None)
                    if styles and isinstance(styles, tuple) and len(styles) == 2:
                        default_style, selected_style = styles
                        btn._style = selected_style if selected else default_style  # type: ignore[attr-defined]
                        btn._redraw()  # type: ignore[attr-defined]
                        btn._apply_state("normal")  # type: ignore[attr-defined]
                except Exception:
                    pass
            else:
                scheme = "primary" if selected else "secondary"
                self._style_tk_button(btn, scheme)
                btn.configure(
                    relief='flat',
                    highlightbackground=PALETTE['accent'] if selected else PALETTE['border'],
                    bd=0,
                )

    def _build_section_card(self, parent, title, subtitle=None):
        card = tk.Frame(
            parent,
            bg=PALETTE['panel'],
            bd=0,
            highlightthickness=1,
            highlightbackground=PALETTE['panel_border'],
        )
        head = tk.Frame(card, bg=PALETTE['surface_alt'], height=30)
        head.pack(fill='x')
        head.pack_propagate(False)
        title_label = tk.Label(
            head,
            text=title,
            bg=PALETTE['surface_alt'],
            fg=PALETTE['header'],
            font=FONTS['label'],
            anchor='w',
            padx=12,
        )
        title_label.pack(fill='x', pady=(4 if subtitle else 5, 0))
        if subtitle:
            tk.Label(
                head,
                text=subtitle,
                bg=PALETTE['surface_alt'],
                fg=PALETTE['muted'],
                font=FONTS['subtitle'],
                anchor='w',
                padx=14,
            ).pack(fill='x', pady=(0, 6))
            head.configure(height=38)
        body = tk.Frame(card, bg=PALETTE['panel'])
        body.pack(fill='both', expand=True, padx=6, pady=6)
        return card, body

    def _build_status_chip(self, parent, label, value, *, bg=None, fg=None):
        # Premium chip with rounded border (no logic change)
        fill = bg or PALETTE['surface']
        border = PALETTE['dash_blue'] if fill == PALETTE['teal_soft'] else PALETTE['border']
        chip = tk.Frame(parent, bg=parent.cget('bg'), bd=0, highlightthickness=0)
        try:
            from modules.ui_premium_widgets import RoundedPanel
            panel = RoundedPanel(
                chip,
                width=180,
                height=38,
                radius=14,
                fill=fill,
                border=border,
                border_width=2,
            )
            panel.pack(fill='x', expand=True)
            inner = tk.Frame(panel, bg=fill)
            inner.place(x=10, y=7, relwidth=1.0, height=24)
        except Exception:
            inner = tk.Frame(
                chip,
                bg=fill,
                bd=0,
                highlightthickness=1,
                highlightbackground=border,
                padx=10,
                pady=6,
            )
            inner.pack(fill='x')

        tk.Label(
            inner,
            text=f"{label}:",
            bg=fill,
            fg=PALETTE['muted'],
            font=FONTS['caption'],
        ).pack(side='left', padx=(0, 6))
        value_label = tk.Label(
            inner,
            text=value,
            bg=fill,
            fg=fg or PALETTE['header'],
            font=FONTS['label'],
        )
        value_label.pack(side='left')
        return chip, value_label

    def _build_elevated_panel(self, parent, *, width=None):
        shell = tk.Frame(parent, bg=PALETTE['shadow_deep'], bd=0, highlightthickness=0)
        if width:
            shell.configure(width=width)
            shell.pack_propagate(False)
        inner = tk.Frame(
            shell,
            bg=PALETTE['panel'],
            bd=0,
            highlightthickness=1,
            highlightbackground=PALETTE['panel_border'],
        )
        inner.pack(fill='both', expand=True, padx=(0, 6), pady=(0, 6))
        return shell, inner

