    def _load_learning_mappings(self):
        path = os.path.join(BASE_DIR, "sec_learned_mappings.json")
        if not os.path.exists(path):
            return None, None
        try:
            with open(path, "r", encoding="utf-8") as f:
                data = json.load(f)
        except Exception:
            return None, None
        try:
            ts = datetime.fromtimestamp(os.path.getmtime(path))
        except Exception:
            ts = None
        return data, ts

    def _refresh_learning_dashboard(self):
        if not hasattr(self, "learning_tree"):
            return
        for item in self.learning_tree.get_children():
            self.learning_tree.delete(item)
        self.learning_detail.delete(0, tk.END)

        data, ts = self._load_learning_mappings()
        if not data:
            self.learning_status.configure(text=self._t('learn_file_missing'))
            return

        categories = sorted(data.keys())
        for cat in categories:
            labels = data.get(cat, [])
            if not isinstance(labels, list):
                continue
            count = len(labels)
            samples = ", ".join(labels[:5]) if labels else "—"
            self.learning_tree.insert('', 'end', values=(cat, count, samples))

        if ts:
            self.learning_status.configure(
                text=f"{self._t('learn_last_updated')}: {ts.strftime('%Y-%m-%d %H:%M')}"
            )
        else:
            self.learning_status.configure(text=self._t('learn_last_updated'))

    def _on_learning_select(self, event):
        selection = self.learning_tree.selection()
        if not selection:
            return
        item = self.learning_tree.item(selection[0])
        values = item.get('values') or []
        if not values:
            return
        category = values[0]
        data, _ = self._load_learning_mappings()
        labels = data.get(category, []) if data else []
        self.learning_detail.delete(0, tk.END)
        for label in labels:
            self.learning_detail.insert(tk.END, label)

    def _update_workspace_context(self, headline=None):
        count = len(self.multi_company_data or {})
        self._refresh_company_selector()
        if hasattr(self, 'workspace_companies_value'):
            self.workspace_companies_value.config(text=str(count))
        if hasattr(self, 'workspace_range_value'):
            try:
                self.workspace_range_value.config(text=f"{self.start_year_var.get()} - {self.end_year_var.get()}")
            except Exception:
                self.workspace_range_value.config(text='--')
        if headline is None:
            ci = (self.current_data or {}).get('company_info', {}) if self.current_data else {}
            ticker = ci.get('ticker') or ''
            name = ci.get('name') or ''
            if ticker:
                headline = f"{name} ({ticker})" if name else ticker
            else:
                headline = self._t('status_ready')
        if hasattr(self, 'workspace_context_label'):
            self.workspace_context_label.config(text=headline)

