        def _n(v):
            try:
                return float(v)
            except Exception:
                return None

        def _fmt_num(v, dec=2):
            nv = _n(v)
            if nv is None:
                return '—'
            return f"{nv:,.{dec}f}"

        def _fmt_pct(v, dec=2):
            nv = _n(v)
            if nv is None:
                return '—'
            return f"{nv * 100:.{dec}f}%"

        def _fmt_b_from_million(v, dec=1):
            nv = _n(v)
            if nv is None:
                return '—'
            return f"{nv / 1000.0:,.{dec}f}"

        def _fmt_money_b(v, dec=1):
            nv = _n(v)
            if nv is None:
                return '—'
            return f"${nv / 1000.0:,.{dec}f}B"

