        # 8) Audit trail and accounting check
        doc.add_heading(L('8. ????? ???????? ????????? ???? ???????', '8. Accounting Integrity and Audit Trail', '8. Intégrité comptable et piste d’audit'), level=2)
        t_a = doc.add_table(rows=1, cols=5)
