    def _comparison_confidence_text(self, confidence) -> str:
        if not isinstance(confidence, (int, float)):
            return self._translate_ui_text('غير متاح')
        conf = float(confidence)
        if conf <= 1.0:
            conf *= 100.0
        return f"{conf:.0f}%"

