    @staticmethod
    def _parent_profile_from_sub_sector(sub_sector: str) -> str:
        s = str(sub_sector or '').strip().lower()
        if s in {'commercial_bank'}:
            return 'bank'
        if s in {'investment_bank'}:
            return 'investment_bank'
        if s in {'insurance_life', 'insurance_pc', 'insurance_broker'}:
            return 'insurance'
        if s in {
            'software_saas',
            'hardware_platform',
            'semiconductor_fabless',
            'semiconductor_idm',
            'integrated_oil',
            'consumer_staples',
            'ev_automaker',
        }:
            return 'industrial'
        return s or 'unknown'

    def _filter_imported_year_dict_by_sector(self, year_dict, sector_profile: str):
        sector = str(sector_profile or '').strip().lower()
        if not isinstance(year_dict, dict) or not sector:
            return year_dict or {}

        bank_only_markers = (
            'LoansReceivable', 'Deposits', 'NetInterestIncome',
            'ProvisionForCreditLosses', 'AllowanceForCreditLosses',
            'FederalFundsSold', 'NoninterestBearingDeposits',
            'DepositLiabilities', 'InterestIncomeOperating',
            'InterestAndDividendIncomeOperating', 'InterestIncomeNet',
        )
        industrial_only_markers = (
            'Inventory', 'CostOfRevenue', 'GrossProfit',
            'ResearchAndDevelopmentExpense', 'SellingGeneralAndAdministrativeExpense',
            'RevenueFromContractWithCustomerExcludingAssessedTax',
        )

        out = {}
        for y, row in (year_dict or {}).items():
            if not isinstance(row, dict):
                out[y] = row
                continue
            filtered = {}
            for k, v in row.items():
                ks = str(k)
                if sector in {'bank', 'commercial_bank', 'investment_bank'}:
                    if any(marker in ks for marker in industrial_only_markers):
                        continue
                else:
                    if any(marker in ks for marker in bank_only_markers):
                        continue
                filtered[k] = v
            out[y] = filtered
        return out

    def _extract_excel_import_metadata(self, ticker_guess, comparison_df=None, methodology_df=None):
        meta = {
            'sector_profile': None,
            'confidence': None,
            'filing_grade': None,
            'out_of_range': False,
        }

        def _norm(v):
            return re.sub(r'[^a-z0-9]+', '', str(v or '').strip().lower())

        if comparison_df is not None and not comparison_df.empty:
            cols = {str(c): _norm(c) for c in comparison_df.columns}
            ticker_col = next((c for c, n in cols.items() if n == 'ticker'), None)
            if ticker_col:
                target = str(ticker_guess or '').strip().upper()
                for _, row in comparison_df.iterrows():
                    row_ticker = str(row.get(ticker_col) or '').strip().upper()
                    if row_ticker != target:
                        continue
                    sector_col = next((c for c, n in cols.items() if n == 'sector'), None)
                    conf_col = next((c for c, n in cols.items() if n == 'confidence'), None)
                    grade_col = next((c for c, n in cols.items() if n in {'filinggrade', 'filing_grade'}), None)
                    oor_col = next((c for c, n in cols.items() if n in {'outofrange', 'out_of_range'}), None)
                    sector_value = str(row.get(sector_col) or '').strip().lower() if sector_col else ''
                    if sector_value and sector_value not in {'unknown', 'none', 'nan'}:
                        meta['sector_profile'] = self._canonical_sector_profile(sector_value)
                    conf_value = self._safe_excel_number(row.get(conf_col)) if conf_col else None
                    if conf_value is not None:
                        meta['confidence'] = float(conf_value)
                    grade_value = str(row.get(grade_col) or '').strip() if grade_col else ''
                    if grade_value:
                        meta['filing_grade'] = grade_value
                    oor_value = str(row.get(oor_col) or '').strip().lower() if oor_col else ''
                    if oor_value in {'yes', 'true', '1'}:
                        meta['out_of_range'] = True
                    break

        if methodology_df is not None and not methodology_df.empty and not meta.get('sector_profile'):
            cols = {str(c): _norm(c) for c in methodology_df.columns}
            topic_col = next((c for c, n in cols.items() if n == 'topic'), None)
            details_col = next((c for c, n in cols.items() if n == 'details'), None)
            if topic_col and details_col:
                sector_tokens = [
                    'technology', 'tech', 'industrial', 'bank', 'insurance',
                    'software_saas', 'hardware_platform', 'semiconductor_fabless',
                    'commercial_bank', 'investment_bank',
                    'insurance_life', 'insurance_pc', 'insurance_broker',
                    'integrated_oil', 'consumer_staples', 'ev_automaker',
                    'energy', 'utilities', 'healthcare', 'consumer',
                    'realestate', 'telecom', 'materials',
                ]
                for _, row in methodology_df.iterrows():
                    topic = _norm(row.get(topic_col))
                    if topic != 'sectorprofile':
                        continue
                    details = self._decode_mojibake_text(str(row.get(details_col) or '')).lower()
                    for token in sector_tokens:
                        if re.search(rf'\b{re.escape(token)}\b', details):
                            meta['sector_profile'] = self._canonical_sector_profile(token)
                            break
                    if meta.get('sector_profile'):
                        break

        if meta.get('confidence') is None and meta.get('sector_profile'):
            meta['confidence'] = 80.0
        if not meta.get('filing_grade'):
            meta['filing_grade'] = 'IN_RANGE_ANNUAL'
        meta['sub_sector_profile'] = self._infer_sub_sector_from_ticker(ticker_guess, meta.get('sector_profile'))
        if meta.get('sub_sector_profile'):
            meta['sector_profile'] = self._parent_profile_from_sub_sector(meta.get('sub_sector_profile'))
        return meta

    @staticmethod
    def _normalize_sector_for_packs(sector_profile: str) -> str:
        s = str(sector_profile or 'unknown').strip().lower()
        # Normalize common plural/synonym forms first (prevents bank flows from falling back to corporate packs).
        if s in ('banks', 'banking', 'bank'):
            return 'bank'
        if s in ('technology', 'tech', 'software_saas', 'hardware_platform', 'semiconductor_fabless',
                 'integrated_oil', 'consumer_staples', 'ev_automaker'):
            return 'industrial'
        if s == 'commercial_bank':
            return 'bank'
        if s == 'investment_bank':
            return 'investment_bank'
        if s == 'insurance_life':
            return 'insurance_life'
        if s == 'insurance_pc':
            return 'insurance_pc'
        if s == 'insurance_broker':
            return 'insurance_broker'
        return s

    INVESTMENT_BANK_REVENUE_LABELS = [
        "NetRevenues",
        "Net revenues",
        "RevenueFromContractWithCustomerExcludingAssessedTax",
        "TotalNetRevenues",
        "NonInterestRevenue",
        "TotalRevenues",
        "Revenues",
        "Revenue",
        "SalesRevenueNet",
    ]

    @classmethod
    def _extract_revenue_investment_bank(cls, raw_sec: dict):
        for label in cls.INVESTMENT_BANK_REVENUE_LABELS:
            try:
                val = raw_sec.get(label) if isinstance(raw_sec, dict) else None
                if val is not None and not (isinstance(val, float) and (math.isnan(val) or math.isinf(val))):
                    return float(val)
            except Exception:
                continue
        try:
            nii = (raw_sec.get("NetInterestIncome", 0) or 0) if isinstance(raw_sec, dict) else 0
            nir = (raw_sec.get("NonInterestRevenue", 0) or 0) if isinstance(raw_sec, dict) else 0
            if float(nii) + float(nir) > 0:
                return float(nii) + float(nir)
        except Exception:
            pass
        return None

    def _extract_revenue_by_sector(self, row: dict, sector_profile: str):
        sector_norm = self._normalize_sector_for_packs(sector_profile)
        if sector_norm in ("investment_bank", "bank", "commercial_bank", "universal_bank"):
            # Banks: do NOT trust generic "Revenues" concepts (can map to OCI / net change items).
            # Canonical: Total Revenue ≈ Net Interest Income + Noninterest Income.
            if isinstance(row, dict):
                def _num(v):
                    try:
                        if v is None:
                            return None
                        fv = float(v)
                        if fv != fv:
                            return None
                        return fv
                    except Exception:
                        return None

                def _as_million_like(v):
                    fv = _num(v)
                    if fv is None:
                        return None
                    return (fv / 1_000_000.0) if abs(fv) >= 100_000_000.0 else fv

                nii = (
                    row.get('NetInterestIncome')
                    or row.get('InterestIncomeExpenseNet')
                    or row.get('InterestIncomeExpenseNetOfProvisionForCreditLoss')
                )
                if nii is None:
                    ii = row.get('InterestIncomeOperating') or row.get('InterestAndDividendIncomeOperating')
                    ie = row.get('InterestExpense') or row.get('InterestAndDebtExpense') or row.get('InterestExpenseDebt')
                    ii = _as_million_like(ii)
                    ie = _as_million_like(ie)
                    if ii not in (None, 0) and ie not in (None, 0):
                        nii = float(ii) - abs(float(ie))
                nii = _as_million_like(nii)
                nonint = (
                    row.get('NoninterestIncome')
                    or row.get('NonInterestIncome')
                    or row.get('TotalNoninterestIncome')
                    or row.get('TotalNonInterestIncome')
                )
                nonint = _as_million_like(nonint)
                if nii not in (None, 0) or nonint not in (None, 0):
                    total = float(nii or 0.0) + float(nonint or 0.0)
                    if abs(total) > 0:
                        return total

            # Fallback to legacy investment-bank extractor if available.
            v = self._extract_revenue_investment_bank(row or {})
            if isinstance(v, (int, float)):
                return float(v)
        if not isinstance(row, dict):
            return None
        preferred = [
            'Revenues',
            'Revenue',
            'SalesRevenueNet',
            'RevenueFromContractWithCustomerExcludingAssessedTax',
            'RevenueFromContractWithCustomerIncludingAssessedTax',
            'TotalRevenue',
            'TotalRevenuesAndOtherIncome',
            'TotalNetRevenues',
            'SalesRevenueServicesNet',
            'NetRevenues',
            'Net revenues',
            'NonInterestRevenue',
        ]
        lower_map = {str(k).strip().lower(): k for k in row.keys()}
        for key in preferred:
            rk = lower_map.get(str(key).strip().lower(), key)
            try:
                val = row.get(rk)
                if val is not None and not pd.isna(val):
                    return float(val)
            except Exception:
                continue
        return None

    @staticmethod
    def _is_present_metric_value(v):
        if v is None:
            return False
        if isinstance(v, str):
            return v.strip() != '' and 'N/A' not in v.upper()
        if isinstance(v, (int, float)):
            try:
                import math
                return not (math.isnan(float(v)) or math.isinf(float(v)))
            except Exception:
                return True
        return True

    def _is_excel_ui_locked(self) -> bool:
        return bool((self.current_data or {}).get('ui_lock_excel'))

    def _merge_financial_analysis_system_ratios(self, ratios_by_year):
        """
        Overlay trusted ratios produced by FinancialAnalysisSystem onto the local
        ratio map without overwriting existing concrete values.
        """
        merged = {}
        for year, row in (ratios_by_year or {}).items():
            try:
                yy = int(year)
            except Exception:
                continue
            merged[yy] = dict(row or {})

        fas = (self.current_data.get('financial_analysis_system', {}) if self.current_data else {}) or {}
        fas_ratios = (fas.get('ratios') or {}) if isinstance(fas, dict) else {}
        fas_map = {
            'ebitda': 'ebitda',
            'gross_margin': 'gross_margin',
            'roe': 'roe',
            'roic': 'roic',
            'peg': 'peg',
        }

        for year, metric_map in (fas_ratios or {}).items():
            try:
                yy = int(year)
            except Exception:
                continue
            rr = merged.setdefault(yy, {})
            reasons = rr.get('_ratio_reasons')
            if not isinstance(reasons, dict):
                rr['_ratio_reasons'] = {}
                reasons = rr['_ratio_reasons']
            for fas_key, ratio_key in fas_map.items():
                record = (metric_map or {}).get(fas_key)
                if isinstance(record, dict):
                    raw_val = record.get('value')
                else:
                    raw_val = record
                num_val = self._safe_excel_number(raw_val)
                current_val = self._safe_excel_number(rr.get(ratio_key))
                if num_val is None or current_val is not None:
                    continue
                rr[ratio_key] = float(num_val)
                rr[f'{ratio_key}_source'] = 'FAS'
                reasons.pop(ratio_key, None)
        return merged

